import React, { createContext, useState, useEffect } from 'react';

// Создаем контекст
export const AppContext = createContext();

export const AppProvider = ({ children }) => {
  const [user, setUser] = useState(null);       // Храним данные вошедшего юзера
  const [products, setProducts] = useState([]); // Все кроссовки из базы
  const [orders, setOrders] = useState([]);     // Заказы текущего юзера

  // 1. Загрузка всех товаров (Read Products)
  const fetchProducts = async () => {
    try {
      const res = await fetch('http://localhost:3001/products');
      const data = await res.json();
      setProducts(data);
    } catch (err) {
      console.error("Ошибка загрузки товаров:", err);
    }
  };

  // 2. Загрузка заказов конкретного пользователя (Relationship 1:N)
  const fetchOrders = async () => {
    if (!user) return;
    try {
      const res = await fetch(`http://localhost:3001/orders?userId=${user.id}`);
      const data = await res.json();
      setOrders(data);
    } catch (err) {
      console.error("Ошибка загрузки заказов:", err);
    }
  };

  // 3. Создание заказа (Create Order)
  const createOrder = async (items) => {
    if (!user) return alert("Войдите в систему!");
    
    const newOrder = {
      userId: user.id,
      items: items,
      date: new Date().toLocaleString(),
      total: items.reduce((sum, item) => sum + item.price, 0)
    };

    try {
      await fetch('http://localhost:3001/orders', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newOrder)
      });
      fetchOrders(); // Обновляем список заказов после покупки
      alert("Заказ успешно оформлен!");
    } catch (err) {
      console.error("Ошибка при создании заказа:", err);
    }
  };

  // 4. Удаление заказа (Delete Order - CRUD)
  const deleteOrder = async (id) => {
    try {
      await fetch(`http://localhost:3001/orders/${id}`, {
        method: 'DELETE'
      });
      // Удаляем из локального состояния, чтобы страница обновилась мгновенно
      setOrders(prev => prev.filter(order => order.id !== id));
    } catch (err) {
      console.error("Ошибка при удалении заказа:", err);
    }
  };

  // При первом запуске загружаем товары
  useEffect(() => {
    fetchProducts();
  }, []);

  // Передаем все функции и состояния в дочерние компоненты
  return (
    <AppContext.Provider value={{ 
      user, 
      setUser, 
      products, 
      orders, 
      createOrder, 
      fetchOrders, 
      deleteOrder // ТЕПЕРЬ ЭТА ФУНКЦИЯ ДОСТУПНА ВЕЗДЕ
    }}>
      {children}
    </AppContext.Provider>
  );
};
export default AdminPage;
